"""Serialize a `RubricsConfig` to YAML and write it to disk."""

from __future__ import annotations

from pathlib import Path
from typing import Any

import yaml

from ai_eval.config.schema import RubricsConfig

_HEADER = """\
# ai-evals rubrics — edit this file to tune metrics, thresholds, and judges.
# Generated by `ai-evals init`. Re-run `ai-evals analyze` after major code changes.
# Docs: https://ai-evals.dev/docs/rubrics
"""


def to_dict(rubrics: RubricsConfig) -> dict[str, Any]:
    """Dump to a YAML-friendly dict (sorted keys for deterministic output)."""
    # `mode="json"` ensures all values are primitives (no Enum / Path objects).
    return rubrics.model_dump(mode="json", exclude_none=True)


def to_yaml(rubrics: RubricsConfig) -> str:
    """Render to a YAML string with header comment."""
    body = yaml.safe_dump(
        to_dict(rubrics),
        sort_keys=False,
        default_flow_style=False,
        indent=2,
    )
    return _HEADER + body


def write(rubrics: RubricsConfig, path: Path) -> None:
    """Write to `path`, creating parent directories as needed."""
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(to_yaml(rubrics), encoding="utf-8")


__all__ = ["to_dict", "to_yaml", "write"]
